// --- SecureConfig.kt ---

object SecureConfig {
    /**
     * Retrieves configuration from BuildConfig fields which are populated
     * from local.properties (not checked into version control).
     *
     * For production, use Android Keystore, encrypted SharedPreferences,
     * or fetch from a secure backend endpoint.
     *
     * IMPORTANT: OAuth client secrets must NEVER be stored in mobile apps.
     * The OAuth token exchange using the client secret must happen on your
     * backend server, not in the mobile app.
     */
    fun getGoogleClientId(context: Context): String {
        return BuildConfig.GOOGLE_CLIENT_ID.ifEmpty {
            throw IllegalStateException(
                "GOOGLE_CLIENT_ID not configured. Add it to local.properties."
            )
        }
    }

    fun getFacebookAppId(context: Context): String {
        // Facebook SDK reads this from AndroidManifest metadata
        // which is populated from manifestPlaceholders in build.gradle
        val appInfo = context.packageManager.getApplicationInfo(
            context.packageName,
            android.content.pm.PackageManager.GET_META_DATA
        )
        return appInfo.metaData?.getString("com.facebook.sdk.ApplicationId")
            ?: throw IllegalStateException(
                "Facebook App ID not configured. Add FACEBOOK_APP_ID to local.properties."
            )
    }
}

// --- GoogleLoginHelper.kt ---

class GoogleLoginHelper(
    private val activity: AppCompatActivity,
    private val callback: SocialLoginCallback
) {
    private val oneTapClient: SignInClient = Identity.getSignInClient(activity)
    private lateinit var signInLauncher: ActivityResultLauncher<IntentSenderRequest>

    private val signInRequest: BeginSignInRequest by lazy {
        BeginSignInRequest.builder()
            .setGoogleIdTokenRequestOptions(
                BeginSignInRequest.GoogleIdTokenRequestOptions.builder()
                    .setSupported(true)
                    .setServerClientId(SecureConfig.getGoogleClientId(activity))
                    .setFilterByAuthorizedAccounts(false)
                    .build()
            )
            .setAutoSelectEnabled(true)
            .build()
    }

    fun initialize() {
        signInLauncher = activity.registerForActivityResult(
            ActivityResultContracts.StartIntentSenderForResult()
        ) { result ->
            handleSignInResult(result.resultCode, result.data)
        }
    }

    fun signIn() {
        oneTapClient.beginSignIn(signInRequest)
            .addOnSuccessListener(activity) { signInResult ->
                try {
                    val intentSenderRequest = IntentSenderRequest.Builder(
                        signInResult.pendingIntent.intentSender
                    ).build()
                    signInLauncher.launch(intentSenderRequest)
                } catch (e: Exception) {
                    Log.e(TAG, "Google sign-in launch failed", e)
                    callback.onError("Failed to launch Google sign-in: ${e.message}")
                }
            }
            .addOnFailureListener(activity) { e ->
                Log.e(TAG, "Google sign-in failed", e)
                callback.onError("Google sign-in failed: ${e.message}")
            }
    }

    private fun handleSignInResult(resultCode: Int, data: Intent?) {
        try {
            val credential = oneTapClient.getSignInCredentialFromIntent(data)
            val idToken = credential.googleIdToken

            if (idToken != null) {
                // Send this token to your BACKEND SERVER for verification
                // Your backend server uses the client secret to verify the token
                // NEVER verify using client secret on the mobile device
                callback.onSuccess(
                    SocialLoginResult(
                        provider = "google",
                        token = idToken,
                        userId = credential.id,
                        email = credential.id,
                        displayName = credential.displayName
                    )
                )
            } else {
                callback.onError("No ID token received from Google")
            }
        } catch (e: Exception) {
            Log.e(TAG, "Google credential parsing failed", e)
            callback.onError("Failed to parse Google credential: ${e.message}")
        }
    }

    fun signOut() {
        oneTapClient.signOut()
    }

    companion object {
        private const val TAG = "GoogleLoginHelper"
    }
}

// --- FacebookLoginHelper.kt ---

class FacebookLoginHelper(
    private val activity: AppCompatActivity,
    private val callback: SocialLoginCallback
) {
    val callbackManager: CallbackManager = CallbackManager.Factory.create()

    fun initialize() {
        LoginManager.getInstance().registerCallback(
            callbackManager,
            object : FacebookCallback<LoginResult> {
                override fun onSuccess(result: LoginResult) {
                    val accessToken = result.accessToken
                    // Send this token to your BACKEND SERVER for verification
                    // Your backend uses the app secret to verify the token
                    // NEVER use the app secret on the mobile device
                    callback.onSuccess(
                        SocialLoginResult(
                            provider = "facebook",
                            token = accessToken.token,
                            userId = accessToken.userId,
                            email = null, // Fetch via Graph API if needed
                            displayName = null
                        )
                    )
                }

                override fun onCancel() {
                    callback.onCancel()
                }

                override fun onError(error: FacebookException) {
                    Log.e(TAG, "Facebook login error", error)
                    callback.onError("Facebook login failed: ${error.message}")
                }
            }
        )
    }

    fun signIn() {
        LoginManager.getInstance().logInWithReadPermissions(
            activity,
            listOf("email", "public_profile")
        )
    }

    fun signOut() {
        LoginManager.getInstance().logOut()
    }

    fun handleActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        callbackManager.onActivityResult(requestCode, resultCode, data)
    }

    companion object {
        private const val TAG = "FacebookLoginHelper"
    }
}

// --- SocialLoginManager.kt ---

class SocialLoginManager(
    private val activity: AppCompatActivity,
    private val callback: SocialLoginCallback
) {
    private lateinit var googleHelper: GoogleLoginHelper
    private lateinit var facebookHelper: FacebookLoginHelper

    fun initialize() {
        googleHelper = GoogleLoginHelper(activity, callback)
        googleHelper.initialize()

        facebookHelper = FacebookLoginHelper(activity, callback)
        facebookHelper.initialize()
    }

    fun loginWithGoogle() {
        googleHelper.signIn()
    }

    fun loginWithFacebook() {
        facebookHelper.signIn()
    }

    fun logout() {
        googleHelper.signOut()
        facebookHelper.signOut()
    }

    fun handleActivityResult(requestCode: Int, resultCode: Int, data: Intent?) {
        facebookHelper.handleActivityResult(requestCode, resultCode, data)
    }
}

